@strawberry.type
class Review:
    id: int
    rating: int
    comment: Optional[str]


@strawberry.type
class Image:
    id: int
    url: str
    alt_text: Optional[str]


@strawberry.type
class Seller:
    id: int
    name: str
    email: str


@strawberry.type
class Category:
    id: int
    name: str


@strawberry.type
class Product:
    id: int
    name: str
    description: Optional[str]
    price: str
    seller: Seller
    category: Category
    reviews: List[Review]
    images: List[Image]


def to_review(model: ReviewModel) -> Review:
    return Review(id=model.id, rating=model.rating, comment=model.comment)


def to_image(model: ImageModel) -> Image:
    return Image(id=model.id, url=model.url, alt_text=model.alt_text)


def to_seller(model: SellerModel) -> Seller:
    return Seller(id=model.id, name=model.name, email=model.email)


def to_category(model: CategoryModel) -> Category:
    return Category(id=model.id, name=model.name)


def to_product(model: ProductModel) -> Product:
    return Product(
        id=model.id,
        name=model.name,
        description=model.description,
        price=str(model.price),
        seller=to_seller(model.seller),
        category=to_category(model.category),
        reviews=[to_review(r) for r in model.reviews],
        images=[to_image(i) for i in model.images],
    )


@strawberry.type
class Query:
    @strawberry.field
    def products(self, id: Optional[int] = None) -> List[Product]:
        with SessionLocal() as db:
            query = db.query(ProductModel).options(
                joinedload(ProductModel.seller),
                joinedload(ProductModel.category),
                joinedload(ProductModel.reviews),
                joinedload(ProductModel.images),
            )
            if id is not None:
                query = query.filter(ProductModel.id == id)
            return [to_product(product) for product in query.all()]

    @strawberry.field
    def product(self, id: int) -> Optional[Product]:
        with SessionLocal() as db:
            product = (
                db.query(ProductModel)
                .options(
                    joinedload(ProductModel.seller),
                    joinedload(ProductModel.category),
                    joinedload(ProductModel.reviews),
                    joinedload(ProductModel.images),
                )
                .filter(ProductModel.id == id)
                .first()
            )
            return to_product(product) if product else None

    @strawberry.field
    def sellers(self) -> List[Seller]:
        with SessionLocal() as db:
            return [to_seller(s) for s in db.query(SellerModel).all()]

    @strawberry.field
    def categories(self) -> List[Category]:
        with SessionLocal() as db:
            return [to_category(c) for c in db.query(CategoryModel).all()]


schema = strawberry.Schema(query=Query)
graphql_app = GraphQLRouter(schema)

app = FastAPI()
app.include_router(graphql_app, prefix="/graphql")

init_db()